struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id using arithmetic operator<<
        stream << packet_id;

        // Serialize username with prefixed adaptor (writes length prefix)
        stream << hexi::prefixed(username);

        // Serialize scores: first write the size, then the vector
        // Using prefixed adaptor for containers which writes count first
        stream << hexi::prefixed(scores);

        // Serialize metadata with null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream with the buffer adaptor
    hexi::binary_stream stream(adaptor);

    // Serialize the packet using the stream's serialise method
    stream.serialise(packet);

    // Return the buffer containing the serialized data
    return buffer;
}
```

