    // Serialize tags vector using prefixed_varint adaptor for compact encoding
    stream_write << hexi::prefixed_varint(packet.tags);

    // Serialize data string using prefixed_varint adaptor for compact encoding
    stream_write << hexi::prefixed_varint(packet.data);

