}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a Hexi binary_stream object for reading
    std::span<uint8_t> non_const_buffer(buffer.data(), buffer.size());
    hexi::buffer_adaptor<std::span<uint8_t>> adaptor_read(non_const_buffer);
    hexi::binary_stream stream_read(adaptor_read);

    // Deserialize packet_id as varint
    stream_read >> packet.packet_id;

    // Deserialize tags vector using prefixed_varint adaptor
    stream_read >> hexi::prefixed_varint(packet.tags);

    // Deserialize data string using prefixed_varint adaptor
    stream_read >> hexi::prefixed_varint(packet.data);

